sql:
SELECT COUNT(*) AS note_count
FROM analyst_notes
WHERE ticker_id = 0;

SELECT ticker_symbol
FROM stock_tickers
WHERE exchange_id = (SELECT exchange_id FROM stock_exchanges WHERE exchange_name = 'NASDAQ');

SELECT COUNT(ticker_id) AS ticker_count
FROM portfolio_tickers
WHERE portfolio_id = 1;

SELECT COUNT(*) AS ticker_count
FROM stock_tickers
WHERE exchange_id = 0;

external_knowledge:
- "past month" refers to the last 30 days; 
- "performing" refers to the average price change percentage; 
- "top 3 performing stocks" means the stocks with the highest average price change percentage in each sector.

sql:
