FROM stock_tickers
WHERE exchange_id = (SELECT exchange_id FROM stock_exchanges WHERE exchange_name = 'NASDAQ');

external_knowledge:
- 'Bank stocks' refers to stocks in the 'Banking' industry; 
- 'last month' refers to the last 30 days from the current date; 
- 'trading days' refers to days with recorded prices in the 'historical_prices' table.
